"use client";
export default function MetricsTable({ metrics, summary }) {
    if (!metrics || metrics.length === 0)
        return <p className="text-gray-500 text-sm">Nenhuma métrica disponível.</p>;

    return (
        <div>
            <table className="w-full border border-gray-300 text-sm">
                <thead className="bg-gray-100">
                    <tr>
                        {Object.keys(metrics[0]).map((k) => (
                            <th key={k} className="border p-2 text-left capitalize">{k}</th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {metrics.map((m, i) => (
                        <tr key={i} className="hover:bg-gray-50">
                            {Object.values(m).map((v, j) => (
                                <td key={j} className="border p-2">{String(v)}</td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>

            {summary && (
                <div className="mt-4 text-sm text-gray-700">
                    <p><b>Média de Espera:</b> {summary.media_espera}</p>
                    <p><b>Média de Turnaround:</b> {summary.media_turnaround}</p>
                    <p><b>Throughput:</b> {summary.throughput}</p>
                    <p><b>CPU Ociosa:</b> {summary.cpu_ociosa}%</p>
                    <p><b>Trocas de Contexto:</b> {summary.trocas_contexto}</p>
                </div>
            )}
        </div>
    );
}
