"use client";
export default function GanttChart({ renders }) {
    if (!renders || renders.length === 0)
        return <p className="text-gray-500 text-sm">Nenhum dado para exibir.</p>;

    const colors = {
        execucao: "bg-green-500",
        contexto: "bg-red-500",
        deadline: "bg-gray-400",
        pagefault: "bg-blue-300",
    };

    return (
        <div className="flex flex-wrap items-center gap-1">
            {renders.map((r, i) => (
                <div
                    key={i}
                    className={`w-8 h-6 ${colors[r.type] || "bg-gray-300"} flex items-center justify-center text-xs text-white rounded`}
                    title={`${r.id} (${r.type}) - t=${r.time}`}
                >
                    {r.id}
                </div>
            ))}
        </div>
    );
}
