"use client";
import { useState } from "react";

export default function ProcessForm({ processes, setProcesses }) {
    const [form, setForm] = useState({
        id: "",
        chegada: "",
        execucao: "",
        prioridade: "",
        deadline: "",
    });

    const handleAdd = () => {
        if (!form.id) return;
        setProcesses([
            ...processes,
            {
                ...form,
                chegada: Number(form.chegada),
                execucao: Number(form.execucao),
                prioridade: Number(form.prioridade),
                deadline: Number(form.deadline),
            },
        ]);
        setForm({ id: "", chegada: "", execucao: "", prioridade: "", deadline: "" });
    };

    return (
        <div className="mt-6 space-y-3">
            <h3 className="font-semibold text-gray-800">Processos</h3>

            <div className="grid grid-cols-5 gap-2">
                {Object.keys(form).map((field) => (
                    <input
                        key={field}
                        placeholder={field}
                        value={form[field]}
                        onChange={(e) => setForm({ ...form, [field]: e.target.value })}
                        className="border rounded-md p-2 text-sm"
                    />
                ))}
            </div>

            <button
                onClick={handleAdd}
                className="px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700"
            >
                Adicionar
            </button>

            {processes.length > 0 && (
                <ul className="mt-2 text-sm list-disc pl-4 text-gray-700">
                    {processes.map((p) => (
                        <li key={p.id}>
                            {p.id} — chegada {p.chegada}, execução {p.execucao}
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}
